using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder — happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithNonEmptyId()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.IsNotEmpty(order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = CreateItems(("Widget", 25.50m, 3));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(76.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalAcrossAllItems()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 4));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert — (10*2) + (5*4) = 40
        Assert.AreEqual(40m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsGreaterThanOrEqual(order.CreatedAt, before);
        Assert.IsLessThanOrEqual(order.CreatedAt, after);
    }

    [TestMethod]
    public void CreateOrder_StoresItemsOnOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1), ("Gadget", 5m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.HasCount(2, order.Items);
    }

    #endregion

    #region CreateOrder — validation

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsMatchingOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var found = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(found);
        Assert.AreSame(created, found);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAllForCustomer()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-B", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("nobody");

        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomersOrders()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-X", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-Y");

        // Assert
        Assert.IsEmpty(orders);
    }

    #endregion
}

